INSERT INTO `components_sections_hero_blocks` (`id`, `kicker`, `title`, `subtitle`) VALUES
(1064, 'Doanh nghiệp tài chính uy tín', 'Giải pháp chứng khoán toàn diện cho nhà đầu tư hiện đại', 'Tối ưu quyết định đầu tư bằng dữ liệu, nghiên cứu và nền tảng giao dịch hiệu suất cao.'),
(1065, 'Về chúng tôi', 'Đối tác tin tưởng cùng đồng hành với bạn trên thị trường chứng khoán', 'Shinhan Investment đã mua lại cổ phần Chứng khoán Nam An vào tháng 7/2015 và thành lập Công ty TNHH Chứng khoán Shinhan Việt Nam vào tháng 2/2016.'),
(1066, 'Hỗ trợ', 'Mở tài khoản trực tuyến trong vài bước', 'Khách hàng cá nhân có thể hoàn tất eKYC ngay trên thiết bị di động hoặc máy tính có camera.'),
(1067, 'Hỗ trợ', 'Các thao tác giao dịch phổ biến', 'Nội dung được nhóm theo luồng thực tế: đăng nhập, funding và quản lý tài khoản.'),
(1068, 'Hỗ trợ', 'Các quy tắc cốt lõi trước khi đặt lệnh', 'Khung giờ, bước giá, lô giao dịch và thanh toán được hệ thống hóa để dễ tra cứu.'),
(1069, 'Hỗ trợ', 'Tìm nhanh câu trả lời cho những thắc mắc phổ biến', 'Tổng hợp các câu hỏi thường gặp theo nhóm vấn đề để người dùng tra cứu nhanh hơn.'),
(1070, 'Hỗ trợ', 'Thông báo vận hành và cập nhật quan trọng', 'Khách hàng nên kiểm tra thường xuyên để nắm sớm thay đổi về giao dịch, quy định và lịch nghỉ.'),
(1071, 'Hỗ trợ', 'Đăng ký giao dịch ký quỹ', 'Trang này tóm tắt điều kiện, quy trình và lưu ý chính khi sử dụng dịch vụ margin.'),
(1072, 'Sản phẩm & Dịch vụ', 'Giải pháp đầu tư cho từng nhu cầu', 'Từ môi giới chứng khoán, giao dịch trực tuyến đến ngân hàng đầu tư, nội dung được sắp xếp theo đúng hành trình sử dụng của khách hàng.'),
(1073, 'Tin tức', 'Dòng tin giúp nhà đầu tư đi trước thị trường', 'Tổng hợp thông báo vận hành, chương trình ưu đãi và cập nhật thị trường theo một trục thông tin duy nhất.'),
(1074, 'Sự kiện', 'Kết nối với cập nhật chiến lược và cộng đồng đầu tư', 'Các buổi workshop, briefing thị trường và hoạt động cộng đồng được tổ chức thành một luồng nội dung thống nhất.'),
(1075, 'Trusted financial institution', 'End-to-end securities solutions for modern investors', 'Make better investment decisions with trusted data, research, and high-performance trading systems.'),
(1076, 'About us', 'A trusted partner accompanying your journey in equity markets', 'Shinhan Investment acquired Nam An Securities in July 2015 and established Shinhan Securities Vietnam in February 2016.'),
(1077, 'Support', 'Open your account online in a few steps', 'Domestic individual customers can complete eKYC on a mobile device or a computer with a camera.'),
(1078, 'Support', 'Common trading actions', 'Content is grouped by the real workflow: login, funding, and account management.'),
(1079, 'Support', 'Core rules before placing an order', 'Trading hours, price steps, lot sizes, and settlement are organized for quick reference.'),
(1080, 'Support', 'Find quick answers to common questions', 'Frequently asked questions are grouped by topic so users can search faster.'),
(1081, 'Support', 'Operational notices and key updates', 'Customers should check regularly for changes to trading, rules and holiday schedules.'),
(1082, 'Support', 'Register for margin trading', 'This page summarizes the main conditions, process and notes for using margin services.'),
(1083, 'Products & Services', 'Investment solutions for every client need', 'From securities brokerage and online trading to investment banking, the content is structured around the customer journey.'),
(1084, 'News', 'A feed that helps investors stay ahead', 'Operational notices, promotions and market updates are grouped into one consistent information stream.'),
(1085, 'Events', 'Connect with strategy updates and the investor community', 'Workshops, market briefings and community activities are organized into a single editorial track.');

