INSERT INTO `components_sections_rich_text_blocks` (`id`, `title`, `content`) VALUES
(721, 'Chúng tôi là ai', '<p>Shinhan Investment là công ty con có 100% vốn của Tập đoàn Tài chính Shinhan, vào tháng 7 năm 2015 đã mua lại cổ phần của Chứng khoán Nam An tại Việt Nam và thành lập nên Công ty TNHH Chứng khoán Shinhan Việt Nam (“Chứng khoán Shinhan”) vào tháng 2 năm 2016.</p><p>Thông qua mạng lưới rộng khắp toàn cầu của Tập đoàn tài chính Shinhan và tại Việt Nam, Chứng Khoán Shinhan ưu tiên đặt mục tiêu hàng đầu với vai trò là \"Người dẫn đường\" cho sự đầu tư thành công để tạo ra giá trị mà khách hàng mong muốn và thiết kế một tương lai tốt đẹp hơn.</p>'),
(722, 'Ban lãnh đạo', '<p>Thông qua mạng lưới “One Shinhan” của Tập đoàn Tài chính Shinhan, bao gồm ngân hàng, Công ty thẻ và Công ty tài chính, chúng tôi cung cấp nhiều dịch vụ đa dạng khác nhau vượt qua các rào cản giữa các lĩnh vực tài chính.</p><p>Ngoài ra, chúng tôi hứa hẹn phát triển công ty thành công ty chứng khoán hàng đầu Việt Nam với mục đích cung cấp các giải pháp tài chính tối ưu cho khách hàng thông qua các bí quyết tài chính tiên tiến trong lĩnh vực quản lý tài sản cá nhân và tài chính doanh nghiệp.</p>'),
(723, 'Shinhan Way', '<p>Tuyên bố sứ mệnh, giá trị cốt lõi và tầm nhìn thể hiện Đường hướng của Shinhan đại diện cho một hệ thống giá trị mà qua đó tất cả các thành viên của tập đoàn tài chính Shinhan đo lường suy nghĩ và hành động của họ.</p><p><strong>Tuyên bố sứ mệnh:</strong> Một thế giới tốt hơn thông qua Tài chính Shinhan.</p><p><strong>Giá trị cốt lõi:</strong> Khách hàng, Tôn trọng lẫn nhau, Thay đổi, Xuất sắc, Quyền sở hữu.</p><p><strong>Tầm nhìn:</strong> Tập đoàn tài chính đẳng cấp thế giới.</p>'),
(724, 'Thông điệp One Shinhan', '<p>Bằng góc độ của khách hàng, chúng tôi luôn cố gắng hết sức để đáp ứng những trải nghiệm và nhu cầu đa dạng với các sản phẩm và dịch vụ tốt nhất tập hợp bởi Tập đoàn Shinhan.</p>'),
(725, 'Quy trình cơ bản', '<p>1. Tải ứng dụng San Xin Ha.</p><p>2. Chọn mở tài khoản và nhập thông tin cá nhân.</p><p>3. Hoàn tất định danh, xác nhận hợp đồng và chờ kích hoạt.</p>'),
(726, NULL, '<p>Chính sách này mô tả cách chúng tôi thu thập, xử lý và bảo vệ dữ liệu cá nhân theo quy định pháp luật hiện hành.</p>'),
(727, NULL, '<p>Người dùng cần tuân thủ điều khoản sử dụng, quyền sở hữu nội dung và các nguyên tắc bảo mật khi truy cập website.</p>'),
(728, NULL, '<p>Nội dung trên website chỉ mang tính tham khảo, không cấu thành khuyến nghị đầu tư bắt buộc.</p>'),
(729, 'Who we are', '<p>Shinhan Investment is a wholly owned subsidiary of Shinhan Financial Group. In Vietnam, it acquired Nam An Securities in July 2015 and officially established Shinhan Securities Vietnam in February 2016.</p><p>Through Shinhan Financial Group’s global network and One Shinhan ecosystem in Vietnam, we position ourselves as a trusted guide for successful investment and long-term value creation.</p>'),
(730, 'Shinhan Way', '<p>Shinhan Way defines the mission, core values, and vision used by all members of Shinhan Financial Group to guide decisions and actions.</p><p><strong>Mission:</strong> A better world through Shinhan finance.</p><p><strong>Core values:</strong> Customer, Mutual Respect, Change, Excellence, Ownership.</p><p><strong>Vision:</strong> A world-class financial group.</p>'),
(731, 'Basic flow', '<p>1. Download the San Xin Ha app.</p><p>2. Choose account opening and enter your personal details.</p><p>3. Complete verification, sign the contract, and wait for activation.</p>'),
(732, NULL, '<p>This policy describes how we collect, process, and protect personal data in accordance with applicable regulations.</p>'),
(733, NULL, '<p>Users must comply with the terms, content ownership principles, and security practices when using this website.</p>'),
(734, NULL, '<p>Website content is for reference only and does not constitute mandatory investment advice.</p>');

