INSERT INTO `components_shared_feature_items` (`id`, `title`, `description`) VALUES
(3257, 'Môi giới chứng khoán', 'Đội ngũ môi giới được đào tạo chuẩn quản trị rủi ro và kỷ luật thực thi.'),
(3258, 'Nền tảng giao dịch', 'Hạ tầng tốc độ cao, quản trị tài khoản đa lớp và cảnh báo danh mục theo thời gian thực.'),
(3259, 'Nghiên cứu chuyên sâu', 'Báo cáo chiến lược, ngành và doanh nghiệp với góc nhìn định lượng.'),
(3260, 'Môi giới chứng khoán', 'Đối tác quản lý tài sản theo đuổi sự tăng trưởng đồng hành cùng khách hàng. Tư vấn đầu tư bởi các chuyên gia tài chính và dịch vụ giao dịch thông qua Nền tảng Kỹ thuật số Sáng tạo.'),
(3261, 'Ngân hàng đầu tư', 'Cung cấp giải pháp tài chính tối ưu cho khách hàng doanh nghiệp. Tận dụng mạng lưới toàn cầu của Tập đoàn Tài chính Shinhan để cung cấp các dịch vụ tư vấn tài chính đa dạng ở thị trường nợ và thị trường vốn nhằm đáp ứng nhu cầu cho khách hàng.'),
(3262, 'Ngân hàng', 'Dịch vụ ngân hàng và hệ sinh thái thanh toán hỗ trợ khách hàng cá nhân, doanh nghiệp.'),
(3263, 'Giải pháp công nghệ', 'Nền tảng công nghệ phục vụ vận hành tài chính và trải nghiệm người dùng nhất quán.'),
(3264, 'Chứng khoán', 'Môi giới, tư vấn đầu tư và dịch vụ ngân hàng đầu tư trong cùng hệ thống One Shinhan.'),
