(1, 'Mở tài khoản cần chuẩn bị giấy tờ gì?', 'mo-tai-khoan-can-gi', '<p>Tài khoản có thể mở trực tuyến bằng eKYC với CCCD/CMND còn hiệu lực.</p>', 0, 1, '2026-04-11 12:42:14.562000', '2026-04-20 16:48:03.017000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi'),
(2, 'Làm thế nào để cấp lại mật khẩu giao dịch?', 'mat-khau-giao-dich', '<p>Khách hàng có thể đặt lại mật khẩu qua ứng dụng hoặc tổng đài hỗ trợ.</p>', 1, 1, '2026-04-11 12:42:14.565000', '2026-04-20 16:48:03.049000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi'),
(3, 'Biểu phí giao dịch có thay đổi theo phân khúc không?', 'phi-giao-dich-co-thay-doi', '<p>Biểu phí có thể thay đổi theo giá trị giao dịch và chính sách từng thời kỳ.</p>', 2, 1, '2026-04-11 12:42:14.568000', '2026-04-20 16:48:03.078000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi'),
(4, 'FinTrust có hỗ trợ giao dịch ký quỹ không?', 'co-ho-tro-margin-khong', '<p>Có. Danh mục cổ phiếu ký quỹ và tỷ lệ cấp hạn mức được cập nhật định kỳ.</p>', 3, 0, '2026-04-11 12:42:14.571000', '2026-04-20 16:48:03.107000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi'),
(5, 'Cách cập nhật thông tin cá nhân?', 'doi-thong-tin-ca-nhan', '<p>Khách hàng có thể cập nhật trực tuyến hoặc tại quầy giao dịch gần nhất.</p>', 4, 0, '2026-04-11 12:42:14.573000', '2026-04-20 16:48:03.135000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi'),
(6, 'Khung giờ tổng đài hỗ trợ?', 'thoi-gian-ho-tro', '<p>Tổng đài hoạt động 8:00 - 17:30 từ thứ Hai đến thứ Sáu.</p>', 5, 0, '2026-04-11 12:42:14.575000', '2026-04-20 16:48:03.152000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi'),
(7, 'What documents are required for account opening?', 'required-documents-account-opening', '<p>Accounts can be opened online via eKYC with valid ID documents.</p>', 0, 1, '2026-04-11 12:42:14.752000', '2026-04-20 16:48:05.870000', '2026-04-20 16:47:59.478000', NULL, NULL, 'en'),
(8, 'How do I reset my trading password?', 'reset-trading-password', '<p>Password reset is available via mobile app or customer hotline.</p>', 1, 1, '2026-04-11 12:42:14.754000', '2026-04-20 16:48:05.884000', '2026-04-20 16:47:59.478000', NULL, NULL, 'en'),
(9, 'Do service fees vary by client segment?', 'service-fee-policy', '<p>Fee policy may vary based on transaction value and service package.</p>', 2, 1, '2026-04-11 12:42:14.757000', '2026-04-20 16:48:05.902000', '2026-04-20 16:47:59.478000', NULL, NULL, 'en'),
(10, 'Does FinTrust provide margin support?', 'margin-support', '<p>Yes. Margin-eligible list and limits are updated periodically.</p>', 3, 0, '2026-04-11 12:42:14.759000', '2026-04-20 16:48:05.914000', '2026-04-20 16:47:59.478000', NULL, NULL, 'en'),
(11, 'How can I update personal information?', 'update-personal-information', '<p>You can update online or at the nearest branch office.</p>', 4, 0, '2026-04-11 12:42:14.761000', '2026-04-20 16:48:05.931000', '2026-04-20 16:47:59.478000', NULL, NULL, 'en'),
(12, 'What are customer hotline operating hours?', 'hotline-hours', '<p>Hotline runs from 8:00 to 17:30, Monday to Friday.</p>', 5, 0, '2026-04-11 12:42:14.763000', '2026-04-20 16:48:05.962000', '2026-04-20 16:47:59.478000', NULL, NULL, 'en');

