(1, 'Thị trường quý 2/2026: Thanh khoản cải thiện tại nhóm vốn hóa lớn', 'thi-truong-giao-dich-quy-2-2026', 'Bản tin cập nhật diễn biến thị trường, chính sách và hoạt động doanh nghiệp liên quan đến nhà đầu tư.', '<p>Nội dung bài viết mẫu nhằm minh họa cách vận hành chuyên mục tin tức, bao gồm góc nhìn thị trường, dữ liệu tham khảo và lưu ý rủi ro.</p>', '2026-04-20 16:48:02.511000', 1, 'published', '2026-04-11 12:42:14.516000', '2026-04-20 16:48:02.533000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi'),
(2, 'Nâng cấp hệ thống giao dịch trực tuyến tháng 4/2026', 'cap-nhat-he-thong-giao-dich-thang-4', 'Bản tin cập nhật diễn biến thị trường, chính sách và hoạt động doanh nghiệp liên quan đến nhà đầu tư.', '<p>Nội dung bài viết mẫu nhằm minh họa cách vận hành chuyên mục tin tức, bao gồm góc nhìn thị trường, dữ liệu tham khảo và lưu ý rủi ro.</p>', '2026-04-19 16:48:02.566000', 1, 'published', '2026-04-11 12:42:14.520000', '2026-04-20 16:48:02.584000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi'),
(3, 'Chiến lược phân bổ ngắn hạn trong giai đoạn biến động', 'chien-luoc-phan-bo-ngan-han', 'Bản tin cập nhật diễn biến thị trường, chính sách và hoạt động doanh nghiệp liên quan đến nhà đầu tư.', '<p>Nội dung bài viết mẫu nhằm minh họa cách vận hành chuyên mục tin tức, bao gồm góc nhìn thị trường, dữ liệu tham khảo và lưu ý rủi ro.</p>', '2026-04-18 16:48:02.607000', 0, 'published', '2026-04-11 12:42:14.523000', '2026-04-20 16:48:02.617000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi'),
(4, 'Triển vọng ngành ngân hàng 2026: Tăng trưởng chọn lọc', 'bao-cao-nganh-ngan-hang-2026', 'Bản tin cập nhật diễn biến thị trường, chính sách và hoạt động doanh nghiệp liên quan đến nhà đầu tư.', '<p>Nội dung bài viết mẫu nhằm minh họa cách vận hành chuyên mục tin tức, bao gồm góc nhìn thị trường, dữ liệu tham khảo và lưu ý rủi ro.</p>', '2026-04-17 16:48:02.630000', 0, 'published', '2026-04-11 12:42:14.526000', '2026-04-20 16:48:02.642000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi'),
(5, 'FinTrust khai trương chi nhánh Đà Nẵng', 'fintrust-khai-truong-chi-nhanh-da-nang', 'Bản tin cập nhật diễn biến thị trường, chính sách và hoạt động doanh nghiệp liên quan đến nhà đầu tư.', '<p>Nội dung bài viết mẫu nhằm minh họa cách vận hành chuyên mục tin tức, bao gồm góc nhìn thị trường, dữ liệu tham khảo và lưu ý rủi ro.</p>', '2026-04-16 16:48:02.661000', 0, 'published', '2026-04-11 12:42:14.529000', '2026-04-20 16:48:02.679000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi'),
