(1, 'Chiến lược ngày 11/04/2026', 'chien-luoc-ngay-11-04-2026', 'Báo cáo mẫu cung cấp góc nhìn chiến lược, dữ liệu định lượng và khuyến nghị theo kịch bản.', '<p>Nội dung báo cáo mẫu cho trung tâm nghiên cứu, có thể mở rộng thêm bảng biểu, biểu đồ và tệp đính kèm.</p>', '2026-04-20 16:48:02.770000', 1, '2026-04-11 12:42:14.542000', '2026-04-20 16:48:02.779000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi'),
