(4, 'Phân tích doanh nghiệp: Ngân hàng A', 'bao-cao-co-phieu-ngan-hang-a', 'Báo cáo mẫu cung cấp góc nhìn chiến lược, dữ liệu định lượng và khuyến nghị theo kịch bản.', '<p>Nội dung báo cáo mẫu cho trung tâm nghiên cứu, có thể mở rộng thêm bảng biểu, biểu đồ và tệp đính kèm.</p>', '2026-04-19 04:48:02.855000', 0, '2026-04-11 12:42:14.554000', '2026-04-20 16:48:02.864000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi'),
