INSERT INTO `services` (`id`, `title`, `slug`, `summary`, `description`, `featured`, `sort_order`, `publish_date`, `status`, `created_at`, `updated_at`, `published_at`, `created_by_id`, `updated_by_id`, `locale`, `advisor_section_title`, `advisor_section_description`) VALUES
(1, 'Môi giới chứng khoán', 'moi-gioi-chung-khoan', 'Giải pháp môi giới cổ phiếu, trái phiếu và chứng chỉ quỹ với tư vấn theo khẩu vị rủi ro.', '<p>Dịch vụ môi giới của FinTrust kết hợp tư vấn đầu tư, quản trị danh mục và hệ thống hỗ trợ quyết định theo dữ liệu thị trường.</p>', 1, 0, '2026-04-20 16:47:59.478000', 'active', '2026-04-11 12:42:14.503000', '2026-04-20 16:48:02.310000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi', NULL, NULL),
(2, 'Giao dịch trực tuyến', 'giao-dich-truc-tuyen', 'Nền tảng giao dịch web/mobile với cảnh báo thông minh và bảo mật nâng cao.', '<p>Khách hàng có thể giao dịch nhiều sản phẩm, theo dõi tài sản thời gian thực và quản trị hạn mức hiệu quả.</p>', 1, 0, '2026-04-20 16:47:59.478000', 'active', '2026-04-11 12:42:14.507000', '2026-04-20 16:48:02.345000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi', NULL, NULL),
(3, 'Tư vấn đầu tư', 'tu-van-dau-tu', 'Khuyến nghị đầu tư theo mục tiêu tài chính và chu kỳ thị trường.', '<p>Đội ngũ chuyên gia hỗ trợ xây dựng chiến lược phân bổ tài sản, tái cân bằng danh mục và giám sát hiệu quả đầu tư.</p>', 1, 0, '2026-04-20 16:47:59.478000', 'active', '2026-04-11 12:42:14.511000', '2026-04-20 16:48:02.428000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi', 'Danh sách chuyên viên tư vấn', 'Chọn tư vấn viên và để lại thông tin để đội ngũ liên hệ sớm.'),
(4, 'Giải pháp tổ chức', 'giai-phap-to-chuc', 'Dịch vụ giao dịch và tư vấn chuyên biệt cho khách hàng doanh nghiệp và tổ chức.', '<p>Chúng tôi cung cấp dịch vụ execution, tư vấn giao dịch khối lớn và báo cáo phân tích chuyên sâu cho khách hàng tổ chức.</p>', 1, 0, '2026-04-20 16:47:59.478000', 'active', '2026-04-11 12:42:14.514000', '2026-04-20 16:48:02.484000', '2026-04-20 16:47:59.478000', NULL, NULL, 'vi', NULL, NULL),
(5, 'Securities Brokerage', 'securities-brokerage', 'Brokerage execution for equities, bonds, and funds with risk-profile guidance.', '<p>FinTrust brokerage combines trade execution, portfolio monitoring, and actionable research coverage.</p>', 1, 0, '2026-04-20 16:47:59.478000', 'active', '2026-04-11 12:42:14.699000', '2026-04-20 16:48:05.267000', '2026-04-20 16:47:59.478000', NULL, NULL, 'en', NULL, NULL),
(6, 'Online Trading', 'online-trading', 'Web and mobile trading platform with smart alerts and robust security.', '<p>Trade multiple products with real-time portfolio visibility and integrated risk controls.</p>', 1, 0, '2026-04-20 16:47:59.478000', 'active', '2026-04-11 12:42:14.702000', '2026-04-20 16:48:05.286000', '2026-04-20 16:47:59.478000', NULL, NULL, 'en', NULL, NULL),
(7, 'Investment Advisory', 'investment-advisory', 'Advisory service aligned with financial goals and market cycles.', '<p>Our advisors support allocation planning, portfolio rebalancing, and investment monitoring.</p>', 1, 0, '2026-04-20 16:47:59.478000', 'active', '2026-04-11 12:42:14.705000', '2026-04-20 16:48:05.324000', '2026-04-20 16:47:59.478000', NULL, NULL, 'en', 'Advisor directory', 'Pick an advisor and leave your details so we can follow up quickly.'),
(8, 'Institutional Solutions', 'institutional-solutions', 'Execution and advisory solutions for corporate and institutional clients.', '<p>Services include block-trade support, customized dealing strategy, and dedicated analytical coverage.</p>', 1, 0, '2026-04-20 16:47:59.478000', 'active', '2026-04-11 12:42:14.708000', '2026-04-20 16:48:05.344000', '2026-04-20 16:47:59.478000', NULL, NULL, 'en', NULL, NULL);

